  ('disabled-57f41407-moex-00257', 'disabled-57f41407', 'disabled-57f41407-moex-113-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '依司法院大法官解釋，關於憲法第8條保障之人身自由，下列何者錯誤？', '["憲法第8條明文保障，故絕對不得以法律限制之", "國家機關僅依思想行狀考核，對已服刑期滿之人民再行交付管訓，與憲 法第8條規定牴觸", "舊刑事訴訟法賦予檢察官羈押被告之權，與憲法第8條之意旨不符", "已廢止之檢肅流氓條例授權警察機關得逕行強制人民到案，無須踐行必 要之司法程序，與憲法第8條意旨不符"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
