  ('disabled-57f41407-moex-00265', 'disabled-57f41407', 'disabled-57f41407-moex-113-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '依司法院大法官解釋及憲法法庭裁判意旨，下列何者與平等原則有違？', '["中央警察大學研究所以色盲為差別待遇分類，符合重要公益，難謂與其 所欲達成之目的欠缺實質關聯性", "立法者得鑒於男女生理之差異，在服兵役事項上為不同之處置", "司法院釋字第728號解釋宣示，依規約得排除女性為祭祀公業之派下員", "立法機關基於憲法價值體系，得斟酌規範事物性質之差異，於服公職事 項上為合理之區別對待"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "5844c0bee1fb", "answer_pdf_sha1": "f068a0f29231", "source_family": "moex-gov-tw", "moex": {"exam_code": "113040", "c": "505", "s": "0308", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "113", "exam_name": "113年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
